		(ProcedureCode IN ('70450','70460','70470','70480','70481','70482','70486','70487','70488',
			'70490','70491','70492','70496','70498','71250','71260','71270','71275',
			'72125','72126','72127','72128','72129','72130','72131','72132','72133',
