	, [IOP] = CASE
	WHEN RevenueCode IN ('905','906') and (y.[ServiceDateFrom] between '2020-04-01' and '2021-03-31') THEN 461 * x.[Quantity] 
	WHEN RevenueCode IN ('905','906') and (y.[ServiceDateFrom] between '2021-04-01' and '2022-03-31') THEN 491 * x.[Quantity] 	
	WHEN RevenueCode IN ('905','906') and (y.[ServiceDateFrom] between '2022-04-01' and '2023-03-31') THEN 523 * x.[Quantity] 	
	WHEN RevenueCode IN ('905','906') and (y.[ServiceDateFrom] between '2023-04-01' and '2024-03-31') THEN 546 * x.[Quantity] 
	WHEN RevenueCode IN ('905','906') and (y.[ServiceDateFrom] between '2024-04-01' and '2025-03-31') THEN 576 * x.[Quantity]
	WHEN RevenueCode IN ('905','906') and (y.[ServiceDateFrom] between '2025-04-01' and '2026-03-31') THEN 612 * x.[Quantity]
	ELSE 0
	END



	, [Psych] = CASE
	WHEN RevenueCode IN ('912','913') and (y.[ServiceDateFrom] between '2020-04-01' and '2021-03-31') THEN  896 * x.[Quantity]
	WHEN RevenueCode IN ('912','913') and (y.[ServiceDateFrom] between '2021-04-01' and '2022-03-31') THEN  954 * x.[Quantity]	
	WHEN RevenueCode IN ('912','913') and (y.[ServiceDateFrom] between '2022-04-01' and '2023-03-31') THEN 1016 * x.[Quantity]		
	WHEN RevenueCode IN ('912','913') and (y.[ServiceDateFrom] between '2023-04-01' and '2024-03-31') THEN 1062 * x.[Quantity]	
	WHEN RevenueCode IN ('912','913') and (y.[ServiceDateFrom] between '2025-04-01' and '2026-03-31') THEN 1187 * x.[Quantity]	
	ELSE 0
	END



	, [ECT] = CASE
	WHEN RevenueCode IN ('901') AND ProcedureCode IN ('90870') and (y.[ServiceDateFrom] between '2020-04-01' and '2021-03-31') THEN 579 * x.[Quantity] 
	WHEN RevenueCode IN ('901') AND ProcedureCode IN ('90870') and (y.[ServiceDateFrom] between '2021-04-01' and '2022-03-31') THEN 616 * x.[Quantity] 	
	WHEN RevenueCode IN ('901') AND ProcedureCode IN ('90870') and (y.[ServiceDateFrom] between '2022-04-01' and '2023-03-31') THEN 656 * x.[Quantity]
	WHEN RevenueCode IN ('901') AND ProcedureCode IN ('90870') and (y.[ServiceDateFrom] between '2023-04-01' and '2024-03-31') THEN 686 * x.[Quantity]
	WHEN RevenueCode IN ('901') AND ProcedureCode IN ('90870') and (y.[ServiceDateFrom] between '2024-04-01' and '2025-03-31') THEN 723 * x.[Quantity]
	WHEN RevenueCode IN ('901') AND ProcedureCode IN ('90870') and (y.[ServiceDateFrom] between '2025-04-01' and '2026-03-31') THEN 766 * x.[Quantity]
	ELSE 0
	END

	, [Miscellaneous] = CASE                                                                                                                                     
	WHEN ProcedureCode = '90785' THEN Round(x.Amount * 0.741, 2)	
	WHEN ProcedureCode = '90839' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '90840' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '97151' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '97152' THEN Round(x.Amount * 0.741, 2)	
	WHEN ProcedureCode = '0359T' THEN Round(x.Amount * 0.741, 2)	
	WHEN ProcedureCode = '0360T' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '0361T' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '0362T' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '0373T' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '97153' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '97154' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '97155' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '97156' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '97157' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = '97158' THEN Round(x.Amount * 0.741, 2)	
	WHEN ProcedureCode = 'G9012' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = 'H0031' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = 'H0032' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = 'H0046' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = 'H2012' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = 'H2014' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = 'H2016' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = 'H2019' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode = 'H2027' THEN Round(x.Amount * 0.741, 2)
	WHEN ProcedureCode in ('90791', '90792') THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 331.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 352.000, IIF(y.[ServiceDateFrom] < '2023-04-01',375.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  392.00, IIF(y.[ServiceDateFrom] < '2025-04-01' , 413.00, 438.00))))) * x.[Quantity] 
	WHEN ProcedureCode = '90832'             THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 143.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 152.000, IIF(y.[ServiceDateFrom] < '2023-04-01',162.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  169.00, IIF(y.[ServiceDateFrom] < '2025-04-01' , 179.00, 190.00))))) * x.[Quantity] 
	WHEN ProcedureCode = '90833'             THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 211.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 225.000, IIF(y.[ServiceDateFrom] < '2023-04-01',239.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  250.00, IIF(y.[ServiceDateFrom] < '2025-04-01' , 264.00, 279.00))))) * x.[Quantity] 
	WHEN ProcedureCode = '90834'             THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 257.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 274.000, IIF(y.[ServiceDateFrom] < '2023-04-01',292.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  305.00, IIF(y.[ServiceDateFrom] < '2025-04-01' , 322.00, 341.00))))) * x.[Quantity] 
	WHEN ProcedureCode = '90836'             THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 315.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 335.000, IIF(y.[ServiceDateFrom] < '2023-04-01',357.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  373.00, IIF(y.[ServiceDateFrom] < '2025-04-01' , 393.00, 418.00))))) * x.[Quantity] 
	WHEN ProcedureCode = '90837'             THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 257.103, IIF(y.[ServiceDateFrom] < '2022-04-01', 272.000, IIF(y.[ServiceDateFrom] < '2023-04-01',291.6126502,IIF(y.[ServiceDateFrom] < '2024-04-01',  304.74, IIF(y.[ServiceDateFrom] < '2025-04-01' , 321.67, 341.00))))) * x.[Quantity]
	WHEN ProcedureCode = '90838'             THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 314.979, IIF(y.[ServiceDateFrom] < '2022-04-01', 335.000, IIF(y.[ServiceDateFrom] < '2023-04-01',357.2570563,IIF(y.[ServiceDateFrom] < '2024-04-01',  373.34, IIF(y.[ServiceDateFrom] < '2025-04-01' , 393.34, 418.00))))) * x.[Quantity]
	WHEN ProcedureCode in ('90846', '90847') THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 258.216, IIF(y.[ServiceDateFrom] < '2022-04-01', 275.000, IIF(y.[ServiceDateFrom] < '2023-04-01',292.8750426,IIF(y.[ServiceDateFrom] < '2024-04-01',  306.06, IIF(y.[ServiceDateFrom] < '2025-04-01' , 322.99, 342.00))))) * x.[Quantity]
	WHEN ProcedureCode in ('90849', '90853') THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 172.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 183.180, IIF(y.[ServiceDateFrom] < '2023-04-01',195.0867000,IIF(y.[ServiceDateFrom] < '2024-04-01',  203.87, IIF(y.[ServiceDateFrom] < '2025-04-01' , 215.33, 228.00))))) * x.[Quantity]
	WHEN ProcedureCode = '90863'             THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 196.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 209.000, IIF(y.[ServiceDateFrom] < '2023-04-01',222.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  232.00, IIF(y.[ServiceDateFrom] < '2025-04-01' , 246.00, 261.00))))) * x.[Quantity]
	WHEN ProcedureCode = '90880'             THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 257.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 274.000, IIF(y.[ServiceDateFrom] < '2023-04-01',292.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  305.00, IIF(y.[ServiceDateFrom] < '2025-04-01' , 322.00, 341.00))))) * x.[Quantity]
	WHEN ProcedureCode = '90901'             THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 243.747, IIF(y.[ServiceDateFrom] < '2022-04-01', 259.000, IIF(y.[ServiceDateFrom] < '2023-04-01',275.8350000,IIF(y.[ServiceDateFrom] < '2024-04-01',  288.25, IIF(y.[ServiceDateFrom] < '2025-04-01' , 304.70, 322.00))))) * x.[Quantity]
	WHEN ProcedureCode in ('96105', '96110', '96112', '96116','96121', '96125','96127', '96130', '96131', '96132', '96133', '96146')   THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 207.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 220.000, IIF(y.[ServiceDateFrom] < '2023-04-01',235.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  245,IIF(y.[ServiceDateFrom] < '2025-04-01',259, 275))))) * x.[Quantity]
	WHEN ProcedureCode in ('96113', '96136', '96137', '96138', '96139') THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 104.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 111.000, IIF(y.[ServiceDateFrom] < '2023-04-01',118.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  123,IIF(y.[ServiceDateFrom] < '2025-04-01', 130, 138))))) * x.[Quantity]
	WHEN ProcedureCode = '99058' THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 424.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 452.000, IIF(y.[ServiceDateFrom] < '2023-04-01',481.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  503,IIF(y.[ServiceDateFrom] < '2025-04-01',530, 562))))) * x.[Quantity]
	WHEN ProcedureCode in ('99241','99242', '99243', '99244', '99245')   THEN IIF(y.[ServiceDateFrom] < '2021-04-01', 328.000, IIF(y.[ServiceDateFrom] < '2022-04-01', 349.000, IIF(y.[ServiceDateFrom] < '2023-04-01',372.0000000,IIF(y.[ServiceDateFrom] < '2024-04-01',  389, IIF(y.[ServiceDateFrom] < '2025-04-01', 410, 435))))) * x.[Quantity]
	ELSE 0																																		
	END	



	, [Sleep_Studies] = CASE
	WHEN ProcedureCode IN ('95782','95873','95800','95801','95805','95806','95807','95808','95810','95811','G0398','G0399','G0400') THEN Round(x.Amount * 0.741, 2)
	ELSE 0
	END



	, [Clinic] = CASE
	WHEN (RevenueCode between 510 and 529) THEN 0.01
	ELSE 0
	END



	, [COVID]=0


Into #Step2
From #Step1_Charges as x

	LEFT JOIN [COL].[Data].[Demo]												                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           as y on x.[EncounterID] = y.[EncounterID]
	-- LEFT JOIN [COL].[Data].[Dx_Px]														    as dp on x.[EncounterID] = dp.[EncounterID] and x.[Sequence] = dp.[Sequence]
	LEFT JOIN [Analytics].[FSG].[Aetna_Market_FS_(2023-2025)]								AS AMFS ON AMFS.[CPT] = x.ProcedureCode AND y.ServiceDateFrom BETWEEN AMFS.StartDate and AMFS.EndDate
	LEFT JOIN [Analytics].[dbo].[Medicare Lab Fee Schedule]								    as LAB1 ON LAB1.[HCPCS] = x.[ProcedureCode] and x.ServiceDateFrom between LAB1.[StartDate] AND LAB1.[EndDate] AND LAB1.[MOD] IS NULL
	LEFT JOIN [Analytics].[FSG].[MedicareFeeSchedule(RBRVS)_Locality1] 						AS LAB2 ON LAB2.[CPT_CODE] = x.[ProcedureCode] and x.ServiceDateFrom between LAB2.[StartDate] AND LAB2.[EndDate]
	LEFT JOIN [FSG].[Medicare Fee Schedule (RBRVS) Locality 1-Cornell and Columbia (2023)]	as LAB2023 ON LAB2023.[CPT CODE] = x.[ProcedureCode]
	LEFT JOIN [Analytics].[dbo].[MAC-Covid-19-Testing]										as COV on COV.[CPT_Code] = x.[ProcedureCode]
	-- LEFT JOIN [Analytics].[dbo].[MedicareFeeSchedule_Locality_1]  							AS M1 ON M1.HCPCS = X.ProcedureCode AND y.ServiceDateFrom BETWEEN M1.StartDate and M1.EndDate
	LEFT JOIN [Analytics].[FSG].[Aetna_AS_List]												AS ASCPT ON ASCPT.[CPT] = x.[ProcedureCode]
	LEFT JOIN [Analytics].[FSG].[Aetna_Drugs_CPTs]											AS Drugs ON Drugs.[CPT] = x.[ProcedureCode]

	LEFT JOIN (
		SELECT
		[HCPCS], [MOD], [StartDate], [EndDate], [Rate], [NON-FAC PE RVU], [WORK RVU], [MP RVU], [MULT PROC], [BILATSURG],
		ROW_NUMBER() OVER (PARTITION BY [HCPCS] order by CASE
							WHEN [Mod] = 'TC' THEN 1
							WHEN [Mod] IN ('26','53') THEN 2
							ELSE 3
							END) AS row_num
	FROM CTE
		) M1
	ON x.procedureCode = M1.[HCPCS] and M1.row_num = 1

ORDER BY [EncounterID], x.[Sequence]

--***********************************************************************************************************************************************************************************************************************************************************************************************************
Select [EncounterID], [ServiceDate], [RevenueCode], [STAT_IND], [ProcedureCode], [Modifier1], [Sequence], [Amount], [BillCharges], [OriginalPayment]

	, [OP_Default]				=IIF([Vascular_Angioplasty]=0 and [Cardiac_Services]=0 and [Clinic]=0 and [Lab]=0 and [Drugs]=0 and [MRI/CT_noReduction]=0 and [MRI/CT_Reduction]=0 and [Radiology/MRI/CT_Scan_NoReduction]=0 and [Radiology/MRI/CT_Scan_Reduction]=0 and [Chemotherapy]=0 and Miscellaneous=0 and Blood_Processing=0 and Blood=0 and  [Radiation_Therapy]=0 and [Implants]=0 and [Implant_V2790]=0 and [implant_C1713]=0 , [OP_Default], 0)
	, [ER]
	, [AS]						= IIF([Minor_Surgery]=0 and [Endoscopy]=0 and [Laparoscopy]=0 and [Cardiac_Cath]=0 and [PTCA]=0 and [Vascular_Angioplasty]=0 and [Cardiac_Services]=0 and [Lithotripsy]=0 and [Gamma_Knife]=0 and [Hip_Knee_Replacement]=0 and [Shoulder_Replacement]=0, [AS], 0)
	, [Minor_Surgery]
	, [Endoscopy]
	, [Laparoscopy]
	, [Cardiac_Cath]
	, [Cardiac_Cath_Injection]
	, [PTCA]
	, [Vascular_Angioplasty]
	, [Cardiac_Services]
	, [Lithotripsy]
	, [Lithotripsy_Injection]
	, [Gamma_Knife]
	, [Hip_Knee_Replacement]
	, [Shoulder_Replacement]
	, [Implants]
	, [Implant_V2790]
	, [implant_C1713]
	, [Blood]
	, [Blood_Processing]
	, [Drugs]		=IIF([Blood]=0 and [Blood_Processing]=0 and (modifier1 not in ('FB','SL') or Modifier1 IS NULL),[Drugs],0)
	, [IV_Therapy]
	, [Chemotherapy]
	, [Lab]

	, [MRI/CT_noReduction]
	, [MRI/CT_Reduction]
	, [Radiology/MRI/CT_Scan_NoReduction]
	, [Radiology/MRI/CT_Scan_Reduction]
	, [ER_Check]

	, LEAD([Radiology/MRI/CT_Scan_Reduction]/1, 0, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD1
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 1, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD2
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 2, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD3
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 3, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD4
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 4, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD5
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 5, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD6
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 6, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD7
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 7, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD8
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 8, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD9
	, LEAD([Radiology/MRI/CT_Scan_Reduction]/2, 9, 0) over (partition by [EncounterID] order by [Radiology/MRI/CT_Scan_Reduction] desc, [Radiology/MRI/CT_Scan_Reduction] Desc) AS RD10

	, LEAD([MRI/CT_Reduction]/1, 0, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC1
	, LEAD([MRI/CT_Reduction]/2, 1, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC2
	, LEAD([MRI/CT_Reduction]/2, 2, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC3
	, LEAD([MRI/CT_Reduction]/2, 3, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC4
	, LEAD([MRI/CT_Reduction]/2, 4, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC5
	, LEAD([MRI/CT_Reduction]/2, 5, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC6
	, LEAD([MRI/CT_Reduction]/2, 6, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC7
	, LEAD([MRI/CT_Reduction]/2, 7, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC8
	, LEAD([MRI/CT_Reduction]/2, 8, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC9
	, LEAD([MRI/CT_Reduction]/2, 9, 0) over (partition by [EncounterID] order by [MRI/CT_Reduction] desc, [MRI/CT_Reduction] Desc) AS RDC10


	, [Radiation_Therapy]


	, LEAD([PT/OT/ST], 0, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy1
	, LEAD([Therapy_MP] * [PT/OT/ST], 1, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy2
	, LEAD([Therapy_MP] * [PT/OT/ST], 2, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy3
	, LEAD([Therapy_MP] * [PT/OT/ST], 3, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy4
	, LEAD([Therapy_MP] * [PT/OT/ST], 4, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy5
	, LEAD([Therapy_MP] * [PT/OT/ST], 5, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy6
	, LEAD([Therapy_MP] * [PT/OT/ST], 6, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy7
	, LEAD([Therapy_MP] * [PT/OT/ST], 7, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy8
	, LEAD([Therapy_MP] * [PT/OT/ST], 8, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy9
	, LEAD([Therapy_MP] * [PT/OT/ST], 9, 0) over (partition by [EncounterID] order by [PT/OT/ST] desc, [PT/OT/ST] Desc) AS Therapy10

	, [IOP]
	, [Psych]
	, [ECT]
	, [Miscellaneous]
	, [Sleep_Studies]
	, [Clinic]			= IIF([Miscellaneous]=0, [Clinic], 0)
	, [COVID]


INTO #Step3
FROM #Step2

--***********************************************************************************************************************************************************************************************************************************************************************************************************
SELECT s.*
        , CAST(0 AS TINYINT) AS NeedsCorrectedClaim
INTO #Step3Bundle
FROM #Step3 s;


/* 
    Modifier = '0' - bundled
    Modifier = '1' - should pay, but needs mod 59/XE/XP/XS/XU 
    Modifier = '9' - always pays
    */

UPDATE b
    SET
        [OP_Default]                        = 0,
		RD1 =0,
		RD2 =0,
		RD3 =0,
		RD4 =0,
		RD5 =0,
		RD6 =0,
		RD7 =0,
		RD8 =0,
		RD9 =0,
		RD10 =0,
		RDC1 =0,
		RDC2 =0,
		RDC3 =0,
		RDC4 =0,
		RDC5 =0,
		RDC6 =0,
		RDC7 =0,
		RDC8 =0,
		RDC9 =0,
		RDC10 =0,
        [Lab]                       = 0
    FROM #Step3Bundle b
	JOIN #Step1_Charges c
	ON c.EncounterID   = b.EncounterID
		AND c.ProcedureCode = b.ProcedureCode
		AND c.Sequence      = b.Sequence
	JOIN [Analytics].[MCR_OPPS].[NCCI_CPT] n
	ON n.CPT = b.ProcedureCode
		AND b.ServiceDate >= n.Effective_Date
    WHERE n.Modifier = '0' and n.DeletionDate is null
	AND EXISTS (
            SELECT 1
	FROM #Step1_Charges p
	WHERE p.EncounterID   = b.EncounterID
		AND p.ProcedureCode = n.CPT_Parent
        );

UPDATE b
    SET NeedsCorrectedClaim = 1
    FROM #Step3Bundle b
	JOIN #Step1_Charges c
	ON c.EncounterID   = b.EncounterID
		AND c.ProcedureCode = b.ProcedureCode
		AND c.Sequence      = b.Sequence
	JOIN [Analytics].[MCR_OPPS].[NCCI_CPT] n
	ON n.CPT = b.ProcedureCode
		AND b.ServiceDate >= n.Effective_Date
        WHERE n.Modifier = '1'
	AND ISNULL(c.Modifier1,'') NOT IN ('59','XE','XP','XS','XU') AND n.DeletionDate is null
	AND EXISTS (
            SELECT 1
	FROM #Step1_Charges p
	WHERE p.EncounterID   = b.EncounterID
		AND p.ProcedureCode = n.CPT_Parent
      );

--***********************************************************************************************************************************************************************************************************************************************************************************************************

Select [EncounterID]

	, SUM([OP_Default])																						AS [OP_Default]
	, MAX([ER])																								AS [ER]
	, MAX([AS])																								AS [AS]
	, MAX([Minor_Surgery])																					AS [Minor_Surgery]
	, MAX([Endoscopy])																						AS [Endoscopy]	
	, MAX([Laparoscopy])																						AS [Laparoscopy]	
	, MAX([Cardiac_Cath])																					AS [Cardiac_Cath]
	, MAX([Cardiac_Cath_Injection])																			AS [Cardiac_Cath_Injection]
	, MAX([PTCA])																							AS [PTCA]
	, SUM([Vascular_Angioplasty])																			AS [Vascular_Angioplasty]
	, SUM([Cardiac_Services])																				AS [Cardiac_Services]
	, MAX([Lithotripsy])																						AS [Lithotripsy]
	, MAX([Lithotripsy_Injection])																			AS [Lithotripsy_Injection]	
	, MAX([Gamma_Knife])																						AS [Gamma_Knife]	
	, MAX([Hip_Knee_Replacement])																			AS [Hip_Knee_Replacement]
	, MAX([Shoulder_Replacement])																			AS [Shoulder_Replacement]
	, SUM([Implants])																						AS [Implants]
	, SUM([Implant_V2790]		) AS [Implant_V2790]
	, SUM([implant_C1713]		) AS [implant_C1713]
	, SUM([Blood])																							AS [Blood]
	, SUM([Blood_Processing])																				AS [Blood_Processing]
	, SUM([Drugs])																							AS [Drugs]
	, SUM([Chemotherapy])																					AS [Chemotherapy]
	, SUM([IV_Therapy])																						AS [IV_Therapy]	
	, SUM([Lab])																								AS [Lab]
	, MAX(RD1)+MAX(RD2)+MAX(RD3)+MAX(RD4)+MAX(RD5)+MAX(RD6)+MAX(RD7)+MAX(RD8)+MAX(RD9)+MAX(RD10) 			AS [Radiology/MRI/CT_Scan_Reduction]
	, MAX(RDC1)+MAX(RDC2)+MAX(RDC3)+MAX(RDC4)+MAX(RDC5)+MAX(RDC6)+MAX(RDC7)+MAX(RDC8)+MAX(RDC9)+MAX(RDC10) 	AS [MRI/CT_Reduction]
	, MAX(Therapy1)+MAX(Therapy2)+MAX(Therapy3)+MAX(Therapy4)+MAX(Therapy5)+MAX(Therapy6)+MAX(Therapy7)+MAX(Therapy8)+MAX(Therapy9)+MAX(Therapy10) 	AS [PT/OT/ST]
	, SUM([Radiation_Therapy])																				AS [Radiation_Therapy]
	, SUM([IOP])																								AS [IOP]
	, SUM([Psych])																							AS [Psych]
	, SUM([ECT])																								AS [ECT]
	, SUM([Miscellaneous])																					AS [Miscellaneous]	
	, SUM([Sleep_Studies])																					AS [Sleep_Studies]
	, MAX([COVID])																							AS [COVID]
	, MAX([Clinic])																							AS [Clinic]
	, SUM([Radiology/MRI/CT_Scan_NoReduction])																AS [Radiology/MRI/CT_Scan_NoReduction]
	, SUM([MRI/CT_noReduction])																				AS [MRI/CT_noReduction]
	, MAX([ER_Check]) AS [ER_Check]
	, MAX(NeedsCorrectedClaim) AS NeedsCorrectedClaim

INTO #Step3_1
FROM #Step3Bundle

GROUP BY [EncounterID]

--***********************************************************************************************************************************************************************************************************************************************************************************************************
