	, SUM([Cardiac_Services])					AS [Cardiac_Services]
	, MAX([Lithotripsy])							AS [Lithotripsy]
	, MAX([Lithotripsy_Injection])				AS [Lithotripsy_Injection]		
	, MAX([Gamma_Knife])							AS [Gamma_Knife]		
