--***********************************************************************************************************************************************************************************************************************************************************************************************************
Select [EncounterID]
	, [Drugs]					= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [AS]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [ER]!=0, 0, [Drugs]) -- Auditor suggestions
	-- ,[Implants]					= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 and [ER]!=0,0,[Implants])

	, [Blood]					= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [AS]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [ER]!=0, 0, [Blood])
	, [Blood_Processing]			= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [AS]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [ER]!=0, 0, [Blood_Processing])	
	, [Gamma_Knife]
	, [Shoulder_Replacement]		= IIF([Gamma_Knife]!=0, 0, [Shoulder_Replacement])
	, [Hip_Knee_Replacement]		= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0, 0, [Hip_Knee_Replacement])
	, [PTCA]						= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0, 0, [PTCA])
	, [Lithotripsy]				= IIF([Gamma_Knife]=0 and [Shoulder_Replacement]=0 and [Hip_Knee_Replacement]=0 and [PTCA]=0, [Lithotripsy],0)
	, [Lithotripsy_Injection]	
	, [Laparoscopy]				= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0, 0, [Laparoscopy])
	, [Cardiac_Cath]				= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0, 0, [Cardiac_Cath])
	, [Cardiac_Cath_Injection]	= IIF([Laparoscopy]	!=0 or[Cardiac_Cath]!=0, [Cardiac_Cath_Injection], 0)
	, [Minor_Surgery]			= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0, 0, [Minor_Surgery])
	, [Endoscopy]				= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0, 0, [Endoscopy])
	, [AS]						= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0, 0, [AS])	
	, [ER]						= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0, 0, [ER])
	, [Psych]					= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0, 0, [Psych])
	, [ECT]						= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0, 0, [ECT])	
	, [IOP]						= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0, 0, [IOP])
	, [Vascular_Angioplasty]		= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Vascular_Angioplasty])
	, [Lab]						= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Lab])
	, [Radiation_Therapy]		= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Radiation_Therapy])
	, [PT/OT/ST]					= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [PT/OT/ST])
	, [Cardiac_Services]			= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Cardiac_Services])
	, [Chemotherapy]				= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Chemotherapy])
	, [Sleep_Studies]			= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Sleep_Studies])
	, [IV_Therapy]				= IIF([Laparoscopy]	!=0 or[Gamma_Knife]!=0 or [PTCA]!=0 or [Cardiac_Cath]!=0 or [Lithotripsy]!=0 or [ECT]!=0 or [ER]!=0 or [IOP]!=0 or [Psych]!=0 or [Lab]!=0, 0, [IV_Therapy])
	, [Miscellaneous]			= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Miscellaneous])
	, [Clinic]					= IIF([Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [Clinic])		

	, [OP_Default]				= IIF([PT/OT/ST]!=0  or [Gamma_Knife]!=0 or [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 or [ER]!=0 or [Psych]!=0 or [ECT]!=0 or [IOP]!=0, 0, [OP_Default])			
	, [COVID]
	
	, [ER_Check]
	, [Radiology/MRI/CT_Scan_Reduction]		=IIF([Gamma_Knife]!=0 OR [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 OR [Psych]!=0 or [ECT]!=0 or [Radiation_Therapy]!=0 OR [IOP]!=0 OR [ER_Check]=1, 0, [Radiology/MRI/CT_Scan_Reduction])
	, [MRI/CT_Reduction]						=IIF([Gamma_Knife]!=0 OR [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 OR [Psych]!=0 or [ECT]!=0 or [Radiation_Therapy]!=0 OR [IOP]!=0 OR [ER_Check]!=1, 0, [MRI/CT_Reduction])
	, [Radiology/MRI/CT_Scan_NoReduction]	=IIF([Gamma_Knife]!=0 OR [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 OR [Psych]!=0 or [ECT]!=0 or [Radiation_Therapy]!=0 OR [IOP]!=0 OR [ER_Check]=1, 0, [Radiology/MRI/CT_Scan_NoReduction])
	, [MRI/CT_noReduction]					=IIF([Gamma_Knife]!=0 OR [Shoulder_Replacement]!=0 or [Hip_Knee_Replacement]!=0 or [PTCA]!=0 or [Lithotripsy]!=0 or [Laparoscopy]!=0 or [Cardiac_Cath]!=0 or [Minor_Surgery]!=0 or [Endoscopy]!=0 or [AS]!=0 OR [Psych]!=0 or [ECT]!=0 or [Radiation_Therapy]!=0 OR [IOP]!=0 OR [ER_Check]!=1, 0, [MRI/CT_noReduction])

	, [Implants]					= CASE 
								WHEN [Implant_V2790]!=0 AND [implant_C1713]!=0 THEN [Implants]+[implant_C1713]
								ELSE IIF([Minor_Surgery]=0 and [er]=0,[Implant_V2790]+[Implants]+[implant_C1713],0)-- Auditor suggestions
								END			
	, [NeedsCorrectedClaim]


INTO #Step4
FROM #Step3_2

--=======================================================================
-- *** [PRICE BREAKDOWN - INSERTED SECTION] ***
-- SOURCE  : #Step3Bundle (post-LEAD slot computation, post-NCCI bundling)
--           joined to #Step4 for encounter-level suppression decisions.
--
-- #Step3Bundle is built as SELECT s.*, CAST(0 AS TINYINT) AS NeedsCorrectedClaim
-- INTO #Step3Bundle FROM #Step3 s — all #Step3 columns survive plus NeedsCorrectedClaim.
-- #Step3 carries an explicit column list that includes all LEAD slot columns
-- (RD1-RD10, RDC1-RDC10, Therapy1-Therapy10) and all pricing category columns.
-- BillCharges, Amount, Quantity, RevenueCode, ProcedureCode, Sequence are all
-- confirmed present in #Step3Bundle via the #Step3 column list.
--
-- MAX CATEGORIES (one winner per encounter):
--   ER, AS, Minor_Surgery, Endoscopy, Laparoscopy,
--   Cardiac_Cath, Cardiac_Cath_Injection, PTCA, Lithotripsy, Lithotripsy_Injection,
--   Gamma_Knife, Hip_Knee_Replacement, Shoulder_Replacement, Clinic, ER_Check, COVID,
--   NeedsCorrectedClaim
--   (COVID and ER_Check and NeedsCorrectedClaim are INDICATOR_FLAG / binary columns)
--
-- SUM CATEGORIES (all matching lines pay):
--   OP_Default, Vascular_Angioplasty, Cardiac_Services,
--   Implants (composed of Implants + Implant_V2790 + implant_C1713),
--   Blood, Blood_Processing, Drugs, IV_Therapy, Chemotherapy, Lab,
--   Radiation_Therapy, IOP, Psych, ECT, Miscellaneous, Sleep_Studies,
--   Radiology/MRI/CT_Scan_NoReduction, MRI/CT_noReduction
--
-- WINDOW_REDUCTION CATEGORIES (slot-based payment via LEAD pivot):
--   Radiology/MRI/CT_Scan_Reduction : slots RD1-RD10  (PARTITION BY EncounterID)
--   MRI/CT_Reduction                : slots RDC1-RDC10 (PARTITION BY EncounterID)
--   PT/OT/ST                        : slots Therapy1-Therapy10 (PARTITION BY EncounterID)
--
-- SUPPRESSION HIERARCHY (from #Step4, tier 1 = highest priority):
--   1.  Gamma_Knife
--   2.  Shoulder_Replacement       (suppressed if Gamma_Knife != 0)
--   3.  Hip_Knee_Replacement       (suppressed if Gamma_Knife OR Shoulder_Replacement != 0)
--   4.  PTCA                       (suppressed if Gamma_Knife OR Shoulder_Replacement OR Hip_Knee_Replacement != 0)
--   5.  Lithotripsy                (suppressed if Gamma_Knife OR Shoulder_Replacement OR Hip_Knee_Replacement OR PTCA != 0)
--   6.  Laparoscopy                (suppressed if any of 1-5 != 0)
--   7.  Cardiac_Cath               (suppressed if Laparoscopy OR any of 1-5 != 0)
--   8.  Cardiac_Cath_Injection     (suppressed unless Laparoscopy OR Cardiac_Cath != 0)
--   9.  Minor_Surgery              (suppressed if Laparoscopy OR Gamma_Knife OR Shoulder_Replacement OR Hip_Knee_Replacement OR PTCA OR Lithotripsy OR Cardiac_Cath != 0)
--  10.  Endoscopy                  (suppressed if Laparoscopy OR any of 1-9 != 0)
--  11.  AS                         (suppressed if Laparoscopy OR any of 1-10 != 0)
--  12.  ER                         (suppressed if Laparoscopy OR any of 1-11 != 0)
--  13.  Psych                      (suppressed if Laparoscopy OR any of 1-12 != 0)
--  14.  ECT                        (suppressed if Psych OR any above != 0)
--  15.  IOP                        (suppressed if Psych OR any above != 0)
--  16.  Vascular_Angioplasty       (suppressed if IOP OR ECT OR Psych or any above != 0)
--  17.  Lab                        (suppressed if IOP OR ECT OR Psych or any above != 0)
--  18.  Radiation_Therapy          (suppressed if IOP OR ECT OR Psych or any above != 0)
--  19.  PT/OT/ST                   (suppressed if IOP OR ECT OR Psych or any above != 0)
--  20.  Cardiac_Services           (suppressed if IOP OR ECT OR Psych or any above != 0)
--  21.  Chemotherapy               (suppressed if IOP OR ECT OR Psych or any above != 0)
--  22.  Sleep_Studies              (suppressed if IOP OR ECT OR Psych or any above != 0)
--  23.  IV_Therapy                 (special: suppressed if Laparoscopy OR Gamma_Knife OR PTCA OR Cardiac_Cath OR Lithotripsy OR ECT OR ER OR IOP OR Psych OR Lab != 0)
--  24.  Miscellaneous              (suppressed if Gamma_Knife OR Shoulder_Replacement OR Hip_Knee_Replacement OR PTCA OR Lithotripsy OR Laparoscopy OR Cardiac_Cath OR Minor_Surgery OR Endoscopy OR AS OR ER OR Psych OR ECT OR IOP != 0)
--  25.  Clinic                     (same condition as Miscellaneous)
--  26.  OP_Default                 (suppressed if PT/OT/ST OR Gamma_Knife OR Shoulder_Replacement OR Hip_Knee_Replacement OR PTCA OR Lithotripsy OR Laparoscopy OR Cardiac_Cath OR Minor_Surgery OR Endoscopy OR AS OR ER OR Psych OR ECT OR IOP != 0)
--  Special: Drugs/Blood/Blood_Processing suppressed if Gamma_Knife OR Shoulder_Replacement OR Hip_Knee_Replacement OR PTCA OR Lithotripsy OR Laparoscopy OR Cardiac_Cath OR AS OR Minor_Surgery OR Endoscopy OR ER != 0
--  Special: Radiology/MRI/CT_Scan_Reduction and MRI/CT_Reduction have complex conditions in #Step4
--  INDICATOR_FLAG: COVID always 0 in this script (hardcoded). ER_Check = binary. NeedsCorrectedClaim = binary.
--=======================================================================

-- BLOCK 1: #bRanked
-- One ROW_NUMBER() per MAX category, HYBRID category (none in this script),
-- WINDOW_REDUCTION category, and INDICATOR_FLAG category.
-- All aggregation passes use GROUP BY EncounterID only (no AGGREGATE_DATE step)
-- so every fixed-rate category is MAX. No HYBRID categories exist.
-- WINDOW_REDUCTION LEAD partitions are all EncounterID_only.
--
-- COUNT CHECK:
--   MAX categories (incl. indicator-flag-like): ER, AS, Minor_Surgery, Endoscopy,
--     Laparoscopy, Cardiac_Cath, Cardiac_Cath_Injection, PTCA, Lithotripsy,
--     Lithotripsy_Injection, Gamma_Knife, Hip_Knee_Replacement, Shoulder_Replacement,
--     Clinic = 14 standard MAX
--   INDICATOR_FLAG (binary, $0): COVID, ER_Check, NeedsCorrectedClaim = 3
--   WINDOW_REDUCTION: Radiology/MRI/CT_Scan_Reduction, MRI/CT_Reduction, PT/OT/ST = 3
--   Total ROW_NUMBER() lines = 14 + 3 + 3 = 20
-- NOTE: Vascular_Angioplasty, Cardiac_Services, Implants, Blood, Blood_Processing,
--   Drugs, IV_Therapy, Chemotherapy, Lab, Radiation_Therapy, IOP, Psych, ECT,
--   Miscellaneous, Sleep_Studies, OP_Default, Radiology/MRI/CT_Scan_NoReduction,
--   MRI/CT_noReduction are SUM — no ROW_NUMBER() needed.
SELECT
    b.*
    -- MAX categories: PARTITION BY [EncounterID]
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[ER]                    DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_ER
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[AS]                    DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_AS_flatrate
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Minor_Surgery]         DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Minor_Surgery
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Endoscopy]             DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Endoscopy
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Laparoscopy]           DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Laparoscopy
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Cardiac_Cath]          DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Cardiac_Cath
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Cardiac_Cath_Injection] DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Cardiac_Cath_Injection
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[PTCA]                  DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_PTCA
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Lithotripsy]           DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Lithotripsy
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Lithotripsy_Injection] DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Lithotripsy_Injection
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Gamma_Knife]           DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Gamma_Knife
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Hip_Knee_Replacement]  DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Hip_Knee_Replacement
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Shoulder_Replacement]  DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Shoulder_Replacement
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[Clinic]                DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_Clinic
    -- INDICATOR_FLAG categories: PARTITION BY [EncounterID], $0 LinePayment
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[COVID]                 DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_COVID
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[ER_Check]              DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_ER_Check
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY b.[NeedsCorrectedClaim]   DESC, b.[Amount] DESC, b.[Sequence] ASC) AS rn_NeedsCorrectedClaim
    -- WINDOW_REDUCTION categories: PARTITION BY EncounterID (lead_partition_by = EncounterID_only)
    -- ORDER BY SUM of ALL slot columns for each category
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY (  ISNULL(b.[RD1],0)+ISNULL(b.[RD2],0)+ISNULL(b.[RD3],0)+ISNULL(b.[RD4],0)+ISNULL(b.[RD5],0)
                    + ISNULL(b.[RD6],0)+ISNULL(b.[RD7],0)+ISNULL(b.[RD8],0)+ISNULL(b.[RD9],0)+ISNULL(b.[RD10],0)) DESC
                  , b.[Amount] DESC, b.[Sequence] ASC) AS rn_Radiology_MRI_CT_Scan_Reduction
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY (  ISNULL(b.[RDC1],0)+ISNULL(b.[RDC2],0)+ISNULL(b.[RDC3],0)+ISNULL(b.[RDC4],0)+ISNULL(b.[RDC5],0)
                    + ISNULL(b.[RDC6],0)+ISNULL(b.[RDC7],0)+ISNULL(b.[RDC8],0)+ISNULL(b.[RDC9],0)+ISNULL(b.[RDC10],0)) DESC
                  , b.[Amount] DESC, b.[Sequence] ASC) AS rn_MRI_CT_Reduction
    , ROW_NUMBER() OVER (PARTITION BY b.[EncounterID]
          ORDER BY (  ISNULL(b.[Therapy1],0)+ISNULL(b.[Therapy2],0)+ISNULL(b.[Therapy3],0)+ISNULL(b.[Therapy4],0)+ISNULL(b.[Therapy5],0)
                    + ISNULL(b.[Therapy6],0)+ISNULL(b.[Therapy7],0)+ISNULL(b.[Therapy8],0)+ISNULL(b.[Therapy9],0)+ISNULL(b.[Therapy10],0)) DESC
                  , b.[Amount] DESC, b.[Sequence] ASC) AS rn_PT_OT_ST
INTO #bRanked
FROM #Step3Bundle b;

-- BLOCK 2: #bSlots
-- Extracts slot values from the rank-1 row for each WINDOW_REDUCTION category per encounter.
-- All three WINDOW_REDUCTION categories use PARTITION BY EncounterID only.
-- Uses GROUP BY + MAX(CASE...) pattern — handles all three window categories in one pass.
SELECT
    [EncounterID]
    -- Radiology/MRI/CT_Scan_Reduction slots (RD1-RD10)
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD1],  0) ELSE 0 END) AS RD1
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD2],  0) ELSE 0 END) AS RD2
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD3],  0) ELSE 0 END) AS RD3
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD4],  0) ELSE 0 END) AS RD4
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD5],  0) ELSE 0 END) AS RD5
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD6],  0) ELSE 0 END) AS RD6
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD7],  0) ELSE 0 END) AS RD7
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD8],  0) ELSE 0 END) AS RD8
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD9],  0) ELSE 0 END) AS RD9
    , MAX(CASE WHEN rn_Radiology_MRI_CT_Scan_Reduction = 1 THEN ISNULL([RD10], 0) ELSE 0 END) AS RD10
    -- MRI/CT_Reduction slots (RDC1-RDC10)
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC1],  0) ELSE 0 END) AS RDC1
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC2],  0) ELSE 0 END) AS RDC2
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC3],  0) ELSE 0 END) AS RDC3
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC4],  0) ELSE 0 END) AS RDC4
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC5],  0) ELSE 0 END) AS RDC5
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC6],  0) ELSE 0 END) AS RDC6
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC7],  0) ELSE 0 END) AS RDC7
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC8],  0) ELSE 0 END) AS RDC8
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC9],  0) ELSE 0 END) AS RDC9
    , MAX(CASE WHEN rn_MRI_CT_Reduction = 1 THEN ISNULL([RDC10], 0) ELSE 0 END) AS RDC10
    -- PT/OT/ST slots (Therapy1-Therapy10)
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy1],  0) ELSE 0 END) AS Therapy1
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy2],  0) ELSE 0 END) AS Therapy2
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy3],  0) ELSE 0 END) AS Therapy3
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy4],  0) ELSE 0 END) AS Therapy4
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy5],  0) ELSE 0 END) AS Therapy5
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy6],  0) ELSE 0 END) AS Therapy6
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy7],  0) ELSE 0 END) AS Therapy7
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy8],  0) ELSE 0 END) AS Therapy8
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy9],  0) ELSE 0 END) AS Therapy9
    , MAX(CASE WHEN rn_PT_OT_ST = 1 THEN ISNULL([Therapy10], 0) ELSE 0 END) AS Therapy10
INTO #bSlots
FROM #bRanked
GROUP BY [EncounterID];

-- BLOCK 3: #LineBreakdown
-- Main line-level breakdown output. One row per charge line from #Step3Bundle.
-- All required columns (RevenueCode, ProcedureCode, Sequence, Amount, BillCharges,
-- Quantity) are confirmed present in #Step3Bundle via column survival trace.
-- Implants sub-columns (Implants, Implant_V2790, implant_C1713) are all confirmed
-- present in #Step3Bundle — ServiceCategory and LinePayment sum all three.
-- BundledByNCCI = b.[NeedsCorrectedClaim] (NCCI bundle step exists in this script).
-- s4 is the authoritative post-suppression source — no suppression re-derivation.
SELECT
    b.[EncounterID]
    , b.[Sequence]
    , b.[ProcedureCode]
    , b.[RevenueCode]
    , b.[ServiceDate]
    , b.[Amount]                AS [BilledAmount]
    , b.[Quantity]
    , b.[BillCharges]

    -- ----------------------------------------------------------------
    -- SERVICE CATEGORY
    -- Hierarchy order matches #Step4 IIF chain exactly.
    -- MAX: IIF(rn=1, name, name_Non_Winner)
    -- SUM: flat label
    -- WINDOW_REDUCTION: rank-based slot label
    -- INDICATOR_FLAG: after dollar categories, $0
    -- ----------------------------------------------------------------
    , [ServiceCategory] = CASE

        -- ---- TIER 1: Gamma_Knife (MAX) ----
        WHEN s4.[Gamma_Knife] != 0
         AND b.[Gamma_Knife] > 0
            THEN IIF(b.rn_Gamma_Knife = 1, 'Gamma_Knife', 'Gamma_Knife_Non_Winner')

        -- ---- TIER 2: Shoulder_Replacement (MAX) ----
        WHEN s4.[Shoulder_Replacement] != 0
         AND b.[Shoulder_Replacement] > 0
            THEN IIF(b.rn_Shoulder_Replacement = 1, 'Shoulder_Replacement', 'Shoulder_Replacement_Non_Winner')

        -- ---- TIER 3: Hip_Knee_Replacement (MAX) ----
        WHEN s4.[Hip_Knee_Replacement] != 0
         AND b.[Hip_Knee_Replacement] > 0
            THEN IIF(b.rn_Hip_Knee_Replacement = 1, 'Hip_Knee_Replacement', 'Hip_Knee_Replacement_Non_Winner')

        -- ---- TIER 4: PTCA (MAX) ----
        WHEN s4.[PTCA] != 0
         AND b.[PTCA] > 0
            THEN IIF(b.rn_PTCA = 1, 'PTCA', 'PTCA_Non_Winner')

        -- ---- TIER 5: Lithotripsy (MAX) ----
        WHEN s4.[Lithotripsy] != 0
         AND b.[Lithotripsy] > 0
            THEN IIF(b.rn_Lithotripsy = 1, 'Lithotripsy', 'Lithotripsy_Non_Winner')

        -- ---- TIER 5b: Lithotripsy_Injection (MAX, always pays if Lithotripsy_Injection != 0) ----
        WHEN s4.[Lithotripsy_Injection] != 0
         AND b.[Lithotripsy_Injection] > 0
            THEN IIF(b.rn_Lithotripsy_Injection = 1, 'Lithotripsy_Injection', 'Lithotripsy_Injection_Non_Winner')

        -- ---- TIER 6: Laparoscopy (MAX) ----
        WHEN s4.[Laparoscopy] != 0
         AND b.[Laparoscopy] > 0
            THEN IIF(b.rn_Laparoscopy = 1, 'Laparoscopy', 'Laparoscopy_Non_Winner')

        -- ---- TIER 7: Cardiac_Cath (MAX) ----
        WHEN s4.[Cardiac_Cath] != 0
         AND b.[Cardiac_Cath] > 0
            THEN IIF(b.rn_Cardiac_Cath = 1, 'Cardiac_Cath', 'Cardiac_Cath_Non_Winner')

        -- ---- TIER 7b: Cardiac_Cath_Injection (MAX) ----
        WHEN s4.[Cardiac_Cath_Injection] != 0
         AND b.[Cardiac_Cath_Injection] > 0
            THEN IIF(b.rn_Cardiac_Cath_Injection = 1, 'Cardiac_Cath_Injection', 'Cardiac_Cath_Injection_Non_Winner')

        -- ---- TIER 8: Minor_Surgery (MAX) ----
        WHEN s4.[Minor_Surgery] != 0
         AND b.[Minor_Surgery] > 0
            THEN IIF(b.rn_Minor_Surgery = 1, 'Minor_Surgery', 'Minor_Surgery_Non_Winner')

        -- ---- TIER 9: Endoscopy (MAX) ----
        WHEN s4.[Endoscopy] != 0
         AND b.[Endoscopy] > 0
            THEN IIF(b.rn_Endoscopy = 1, 'Endoscopy', 'Endoscopy_Non_Winner')

        -- ---- TIER 10: AS (MAX flat rate, rn_AS_flatrate; note: slot-based payment handled below) ----
        WHEN s4.[AS] != 0
         AND b.[AS] > 0
            THEN IIF(b.rn_AS_flatrate = 1, 'AS_Ambulatory_Surgery', 'AS_Ambulatory_Surgery_Non_Winner')

        -- ---- TIER 11: ER (MAX) ----
        WHEN s4.[ER] != 0
         AND b.[ER] > 0
            THEN IIF(b.rn_ER = 1, 'ER', 'ER_Non_Winner')

        -- ---- TIER 12: Psych (SUM) ----
        WHEN s4.[Psych] != 0
         AND b.[Psych] > 0
            THEN 'Psych'

        -- ---- TIER 13: ECT (SUM) ----
        WHEN s4.[ECT] != 0
         AND b.[ECT] > 0
            THEN 'ECT'

        -- ---- TIER 14: IOP (SUM) ----
        WHEN s4.[IOP] != 0
         AND b.[IOP] > 0
            THEN 'IOP'

        -- ---- TIER 15: Vascular_Angioplasty (SUM) ----
        WHEN s4.[Vascular_Angioplasty] != 0
         AND b.[Vascular_Angioplasty] > 0
            THEN 'Vascular_Angioplasty'

        -- ---- TIER 16: Lab (SUM) ----
        WHEN s4.[Lab] != 0
         AND b.[Lab] > 0
            THEN 'Lab'

        -- ---- TIER 17: Radiation_Therapy (SUM) ----
        WHEN s4.[Radiation_Therapy] != 0
         AND b.[Radiation_Therapy] > 0
            THEN 'Radiation_Therapy'

        -- ---- TIER 18: PT/OT/ST (WINDOW_REDUCTION via Therapy1-Therapy10 slots) ----
        WHEN s4.[PT/OT/ST] != 0
         AND (  ISNULL(b.[Therapy1],0)+ISNULL(b.[Therapy2],0)+ISNULL(b.[Therapy3],0)+ISNULL(b.[Therapy4],0)+ISNULL(b.[Therapy5],0)
              + ISNULL(b.[Therapy6],0)+ISNULL(b.[Therapy7],0)+ISNULL(b.[Therapy8],0)+ISNULL(b.[Therapy9],0)+ISNULL(b.[Therapy10],0)) > 0
            THEN CASE
                    WHEN b.rn_PT_OT_ST BETWEEN 1 AND 10 THEN 'PT_OT_ST'
                    ELSE 'PT_OT_ST_Beyond_Max'
                 END

        -- ---- TIER 19: Cardiac_Services (SUM) ----
        WHEN s4.[Cardiac_Services] != 0
         AND b.[Cardiac_Services] > 0
            THEN 'Cardiac_Services'

        -- ---- TIER 20: Chemotherapy (SUM) ----
        WHEN s4.[Chemotherapy] != 0
         AND b.[Chemotherapy] > 0
            THEN 'Chemotherapy'

        -- ---- TIER 21: Sleep_Studies (SUM) ----
        WHEN s4.[Sleep_Studies] != 0
         AND b.[Sleep_Studies] > 0
            THEN 'Sleep_Studies'

        -- ---- TIER 22: IV_Therapy (SUM) ----
        WHEN s4.[IV_Therapy] != 0
         AND b.[IV_Therapy] > 0
            THEN 'IV_Therapy'

        -- ---- TIER 23: Miscellaneous (SUM) ----
        WHEN s4.[Miscellaneous] != 0
         AND b.[Miscellaneous] > 0
            THEN 'Miscellaneous'

        -- ---- TIER 24: Clinic (MAX) ----
        WHEN s4.[Clinic] != 0
         AND b.[Clinic] > 0
            THEN IIF(b.rn_Clinic = 1, 'Clinic', 'Clinic_Non_Winner')

        -- ---- TIER 25: Radiology/MRI/CT_Scan_Reduction (WINDOW_REDUCTION via RD1-RD10) ----
        WHEN s4.[Radiology/MRI/CT_Scan_Reduction] != 0
         AND (  ISNULL(b.[RD1],0)+ISNULL(b.[RD2],0)+ISNULL(b.[RD3],0)+ISNULL(b.[RD4],0)+ISNULL(b.[RD5],0)
              + ISNULL(b.[RD6],0)+ISNULL(b.[RD7],0)+ISNULL(b.[RD8],0)+ISNULL(b.[RD9],0)+ISNULL(b.[RD10],0)) > 0
            THEN CASE
                    WHEN b.rn_Radiology_MRI_CT_Scan_Reduction BETWEEN 1 AND 10 THEN 'Radiology_MRI_CT_Scan_Reduction'
                    ELSE 'Radiology_MRI_CT_Scan_Reduction_Beyond_Max'
                 END

        -- ---- TIER 26: MRI/CT_Reduction (WINDOW_REDUCTION via RDC1-RDC10) ----
        WHEN s4.[MRI/CT_Reduction] != 0
         AND (  ISNULL(b.[RDC1],0)+ISNULL(b.[RDC2],0)+ISNULL(b.[RDC3],0)+ISNULL(b.[RDC4],0)+ISNULL(b.[RDC5],0)
              + ISNULL(b.[RDC6],0)+ISNULL(b.[RDC7],0)+ISNULL(b.[RDC8],0)+ISNULL(b.[RDC9],0)+ISNULL(b.[RDC10],0)) > 0
            THEN CASE
                    WHEN b.rn_MRI_CT_Reduction BETWEEN 1 AND 10 THEN 'MRI_CT_Reduction'
                    ELSE 'MRI_CT_Reduction_Beyond_Max'
                 END

        -- ---- TIER 27: Radiology/MRI/CT_Scan_NoReduction (SUM) ----
        WHEN s4.[Radiology/MRI/CT_Scan_NoReduction] != 0
         AND b.[Radiology/MRI/CT_Scan_NoReduction] > 0
            THEN 'Radiology_MRI_CT_Scan_NoReduction'

        -- ---- TIER 28: MRI/CT_noReduction (SUM) ----
        WHEN s4.[MRI/CT_noReduction] != 0
         AND b.[MRI/CT_noReduction] > 0
            THEN 'MRI_CT_noReduction'

        -- ---- TIER 29: Drugs (SUM) ----
        WHEN s4.[Drugs] != 0
         AND b.[Drugs] > 0
            THEN 'Drugs'

        -- ---- TIER 30: Implants (SUM, composed of Implants + Implant_V2790 + implant_C1713) ----
        WHEN s4.[Implants] != 0
         AND (ISNULL(b.[Implants],0) + ISNULL(b.[Implant_V2790],0) + ISNULL(b.[implant_C1713],0)) > 0
            THEN 'Implants'

        -- ---- TIER 31: Blood (SUM) ----
        WHEN s4.[Blood] != 0
         AND b.[Blood] > 0
            THEN 'Blood'

        -- ---- TIER 32: Blood_Processing (SUM) ----
        WHEN s4.[Blood_Processing] != 0
         AND b.[Blood_Processing] > 0
            THEN 'Blood_Processing'

        -- ---- TIER 33: OP_Default (SUM, catch-all) ----
        WHEN s4.[OP_Default] != 0
         AND b.[OP_Default] > 0
            THEN 'OP_Default'

        -- ---- Suppressed: line matched a category but #Step4 hierarchy zeroed it ----
        WHEN (
              ISNULL(b.[ER],0)                              + ISNULL(b.[AS],0)
            + ISNULL(b.[Minor_Surgery],0)                   + ISNULL(b.[Endoscopy],0)
            + ISNULL(b.[Laparoscopy],0)
            + ISNULL(b.[Cardiac_Cath],0)                    + ISNULL(b.[Cardiac_Cath_Injection],0)
            + ISNULL(b.[PTCA],0)
            + ISNULL(b.[Lithotripsy],0)                     + ISNULL(b.[Lithotripsy_Injection],0)
            + ISNULL(b.[Gamma_Knife],0)
            + ISNULL(b.[Hip_Knee_Replacement],0)            + ISNULL(b.[Shoulder_Replacement],0)
            + ISNULL(b.[Vascular_Angioplasty],0)            + ISNULL(b.[Cardiac_Services],0)
            + ISNULL(b.[Implants],0)                        + ISNULL(b.[Implant_V2790],0)
            + ISNULL(b.[implant_C1713],0)
            + ISNULL(b.[Blood],0)                           + ISNULL(b.[Blood_Processing],0)
            + ISNULL(b.[Drugs],0)
            + ISNULL(b.[IV_Therapy],0)                      + ISNULL(b.[Chemotherapy],0)
            + ISNULL(b.[Lab],0)                             + ISNULL(b.[Radiation_Therapy],0)
            + ISNULL(b.[IOP],0)                             + ISNULL(b.[Psych],0)
            + ISNULL(b.[ECT],0)                             + ISNULL(b.[Miscellaneous],0)
            + ISNULL(b.[Sleep_Studies],0)                   + ISNULL(b.[Clinic],0)
            + ISNULL(b.[OP_Default],0)
            + ISNULL(b.[COVID],0)                           + ISNULL(b.[ER_Check],0)
            + ISNULL(b.[NeedsCorrectedClaim],0)
            + ISNULL(b.[RD1],0)+ISNULL(b.[RD2],0)+ISNULL(b.[RD3],0)+ISNULL(b.[RD4],0)+ISNULL(b.[RD5],0)
            + ISNULL(b.[RD6],0)+ISNULL(b.[RD7],0)+ISNULL(b.[RD8],0)+ISNULL(b.[RD9],0)+ISNULL(b.[RD10],0)
            + ISNULL(b.[RDC1],0)+ISNULL(b.[RDC2],0)+ISNULL(b.[RDC3],0)+ISNULL(b.[RDC4],0)+ISNULL(b.[RDC5],0)
            + ISNULL(b.[RDC6],0)+ISNULL(b.[RDC7],0)+ISNULL(b.[RDC8],0)+ISNULL(b.[RDC9],0)+ISNULL(b.[RDC10],0)
            + ISNULL(b.[Therapy1],0)+ISNULL(b.[Therapy2],0)+ISNULL(b.[Therapy3],0)+ISNULL(b.[Therapy4],0)+ISNULL(b.[Therapy5],0)
            + ISNULL(b.[Therapy6],0)+ISNULL(b.[Therapy7],0)+ISNULL(b.[Therapy8],0)+ISNULL(b.[Therapy9],0)+ISNULL(b.[Therapy10],0)
            + ISNULL(b.[Radiology/MRI/CT_Scan_NoReduction],0) + ISNULL(b.[MRI/CT_noReduction],0)
        ) > 0
            THEN 'Suppressed_By_Hierarchy'

        -- ---- INDICATOR_FLAG: COVID (binary 0/1, placed after all dollar categories) ----
        WHEN b.[COVID] != 0
            THEN IIF(b.rn_COVID = 1, 'COVID_Flag', 'COVID_Flag_Non_Winner')

        -- ---- INDICATOR_FLAG: ER_Check (binary 0/1) ----
        WHEN b.[ER_Check] != 0
            THEN IIF(b.rn_ER_Check = 1, 'ER_Check_Flag', 'ER_Check_Flag_Non_Winner')

        -- ---- INDICATOR_FLAG: NeedsCorrectedClaim (binary 0/1) ----
        WHEN b.[NeedsCorrectedClaim] != 0
            THEN IIF(b.rn_NeedsCorrectedClaim = 1, 'NeedsCorrectedClaim_Flag', 'NeedsCorrectedClaim_Flag_Non_Winner')

        ELSE 'No_Payment_Category'
    END

    -- ----------------------------------------------------------------
    -- PRICING METHOD
    -- Human-readable description of the rate formula for this line.
    -- ----------------------------------------------------------------
    , [PricingMethod] = CASE

        WHEN s4.[Gamma_Knife] != 0
         AND b.[Gamma_Knife] > 0
            THEN 'Contracted flat rate per contract year (Gamma Knife CPT list: G0339/G0340/61796-61800/63620/63621)'

        WHEN s4.[Shoulder_Replacement] != 0
         AND b.[Shoulder_Replacement] > 0
            THEN 'Contracted flat rate per contract year (Shoulder Replacement CPT list: 23470/23472/23473/23474)'

        WHEN s4.[Hip_Knee_Replacement] != 0
         AND b.[Hip_Knee_Replacement] > 0
            THEN 'Contracted flat rate per contract year (Hip/Knee Replacement CPT list: 27130/27132/27437-27447)'

        WHEN s4.[PTCA] != 0
         AND b.[PTCA] > 0
            THEN 'Contracted flat rate per contract year (PTCA CPT list: 92920-92944/92986/92987/92990/C9600-C9608)'

        WHEN s4.[Lithotripsy] != 0
         AND b.[Lithotripsy] > 0
            THEN 'Contracted flat rate per contract year (Lithotripsy CPT 50590)'

        WHEN s4.[Lithotripsy_Injection] != 0
         AND b.[Lithotripsy_Injection] > 0
            THEN 'Lithotripsy Injection - $0 placeholder column under current contract terms'

        WHEN s4.[Laparoscopy] != 0
         AND b.[Laparoscopy] > 0
            THEN 'Contracted flat rate per contract year (Laparoscopy CPT list: 38120-38589/43279-60659/G0342/S2079)'

        WHEN s4.[Cardiac_Cath] != 0
         AND b.[Cardiac_Cath] > 0
            THEN 'Contracted flat rate per contract year (Cardiac Cath CPT list: G0448/C9758/0408T-0632T/33017-34718/92978/92979/93451-93592)'

        WHEN s4.[Cardiac_Cath_Injection] != 0
         AND b.[Cardiac_Cath_Injection] > 0
            THEN 'Cardiac Cath Injection - $0 placeholder column under current contract terms'

        WHEN s4.[Minor_Surgery] != 0
         AND b.[Minor_Surgery] > 0
            THEN 'Contracted flat rate per contract year (Minor Surgery CPT list: 10030-69210)'

        WHEN s4.[Endoscopy] != 0
         AND b.[Endoscopy] > 0
            THEN 'Contracted flat rate per contract year (Endoscopy CPT numeric ranges: 31615-31651/43191-43278/44360-44408/45300-45398)'

        WHEN s4.[AS] != 0
         AND b.[AS] > 0
            THEN 'Contracted flat rate per contract year (Ambulatory Surgery CPT in Aetna_AS_List with Rev 36x/49x/75x/79x/480/481; excl 93005/93580)'

        WHEN s4.[ER] != 0
         AND b.[ER] > 0
            THEN 'Contracted flat rate per contract year by Rev code (ER Rev 450/451/452/459 = standard rate; Rev 456 = lower rate)'

        WHEN s4.[Psych] != 0
         AND b.[Psych] > 0
            THEN 'Contracted per diem x Quantity per contract year (Psych Rev 912/913)'

        WHEN s4.[ECT] != 0
         AND b.[ECT] > 0
            THEN 'Contracted flat rate x Quantity per contract year (ECT Rev 901 + CPT 90870)'

        WHEN s4.[IOP] != 0
         AND b.[IOP] > 0
            THEN 'Contracted per diem x Quantity per contract year (IOP Rev 905/906)'

        WHEN s4.[Vascular_Angioplasty] != 0
         AND b.[Vascular_Angioplasty] > 0
            THEN 'Pct of charges: Amount x 74.1% (Vascular Angioplasty CPT numeric 93880-93998)'

        WHEN s4.[Lab] != 0
         AND b.[Lab] > 0
            THEN 'Medicare Lab Fee Schedule (LAB1) or RBRVS Locality 1 (LAB2) x period multiplier x Quantity (Lab CPT ranges 80047-89356 and supplemental list)'

        WHEN s4.[Radiation_Therapy] != 0
         AND b.[Radiation_Therapy] > 0
            THEN 'Pct of charges: Amount x 74.1% (Radiation Therapy Rev 331/332/333/335 excl chemo CPTs; or A9517/A9527/A9530/A9543/A9604/A9699)'

        WHEN s4.[PT/OT/ST] != 0
         AND (  ISNULL(b.[Therapy1],0)+ISNULL(b.[Therapy2],0)+ISNULL(b.[Therapy3],0)+ISNULL(b.[Therapy4],0)+ISNULL(b.[Therapy5],0)
              + ISNULL(b.[Therapy6],0)+ISNULL(b.[Therapy7],0)+ISNULL(b.[Therapy8],0)+ISNULL(b.[Therapy9],0)+ISNULL(b.[Therapy10],0)) > 0
            THEN CASE
                    WHEN b.rn_PT_OT_ST = 1  THEN 'PT/OT/ST: Amount x 74.1% - 1st therapy procedure, full rate'
                    WHEN b.rn_PT_OT_ST BETWEEN 2 AND 10
                                            THEN 'PT/OT/ST: Amount x 74.1% x multiple-procedure reduction factor (Aetna policy) - 2nd+ therapy procedure'
                    ELSE 'PT/OT/ST: Beyond 10th therapy procedure in encounter - $0'
                 END

        WHEN s4.[Cardiac_Services] != 0
         AND b.[Cardiac_Services] > 0
            THEN 'Pct of charges: Amount x 74.1% (Cardiac Services CPT numeric 93000-93354; or 0541T/0542T)'

        WHEN s4.[Chemotherapy] != 0
         AND b.[Chemotherapy] > 0
            THEN 'Pct of charges: Amount x 74.1% (Chemotherapy CPT: 51720/Q0083-Q0085 or CPT numeric 96401-96542)'

        WHEN s4.[Sleep_Studies] != 0
         AND b.[Sleep_Studies] > 0
            THEN 'Pct of charges: Amount x 74.1% (Sleep Studies CPT: 95782/95873/95800/95801/95805-95811/G0398/G0399/G0400)'

        WHEN s4.[IV_Therapy] != 0
         AND b.[IV_Therapy] > 0
            THEN 'IV Therapy - $0 placeholder column under current contract terms'

        WHEN s4.[Miscellaneous] != 0
         AND b.[Miscellaneous] > 0
            THEN 'Miscellaneous: Amount x 74.1% or contracted flat rate per CPT/period (specific CPT list: 90785/90791/90792/90832-90901 etc.)'

        WHEN s4.[Clinic] != 0
         AND b.[Clinic] > 0
            THEN 'Clinic indicator: $0.01 marker for Rev 510-529 - used as flag, not a payment amount'

        WHEN s4.[Radiology/MRI/CT_Scan_Reduction] != 0
         AND (  ISNULL(b.[RD1],0)+ISNULL(b.[RD2],0)+ISNULL(b.[RD3],0)+ISNULL(b.[RD4],0)+ISNULL(b.[RD5],0)
              + ISNULL(b.[RD6],0)+ISNULL(b.[RD7],0)+ISNULL(b.[RD8],0)+ISNULL(b.[RD9],0)+ISNULL(b.[RD10],0)) > 0
            THEN CASE
                    WHEN b.rn_Radiology_MRI_CT_Scan_Reduction = 1
                        THEN 'Radiology/MRI/CT Scan: Amount x 74.1% - 1st procedure, full rate (MULT PROC=4 or BILATSURG=1; CT/MRI CPT list or 70010-79999 range)'
                    WHEN b.rn_Radiology_MRI_CT_Scan_Reduction BETWEEN 2 AND 10
                        THEN 'Radiology/MRI/CT Scan: Amount x 74.1% / 2 - 2nd+ multiple-procedure reduction (MULT PROC=4 or BILATSURG=1)'
                    ELSE 'Radiology/MRI/CT Scan: Beyond 10th procedure in encounter - $0'
                 END

        WHEN s4.[MRI/CT_Reduction] != 0
         AND (  ISNULL(b.[RDC1],0)+ISNULL(b.[RDC2],0)+ISNULL(b.[RDC3],0)+ISNULL(b.[RDC4],0)+ISNULL(b.[RDC5],0)
              + ISNULL(b.[RDC6],0)+ISNULL(b.[RDC7],0)+ISNULL(b.[RDC8],0)+ISNULL(b.[RDC9],0)+ISNULL(b.[RDC10],0)) > 0
            THEN CASE
                    WHEN b.rn_MRI_CT_Reduction = 1
                        THEN 'MRI/CT (ER context): Amount x 74.1% - 1st procedure, full rate (MULT PROC=4 or BILATSURG=1; MRI/CT CPT sub-list; ER_Check != 1)'
                    WHEN b.rn_MRI_CT_Reduction BETWEEN 2 AND 10
                        THEN 'MRI/CT (ER context): Amount x 74.1% / 2 - 2nd+ multiple-procedure reduction (MULT PROC=4 or BILATSURG=1)'
                    ELSE 'MRI/CT (ER context): Beyond 10th procedure in encounter - $0'
                 END

        WHEN s4.[Radiology/MRI/CT_Scan_NoReduction] != 0
         AND b.[Radiology/MRI/CT_Scan_NoReduction] > 0
            THEN 'Radiology/MRI/CT Scan NoReduction: Amount x 74.1% - No multiple-procedure reduction (MULT PROC not 4; CT/MRI CPT list or 70010-79999 range)'

        WHEN s4.[MRI/CT_noReduction] != 0
         AND b.[MRI/CT_noReduction] > 0
            THEN 'MRI/CT NoReduction (ER context): Amount x 74.1% - No multiple-procedure reduction (MULT PROC not 4; MRI/CT CPT sub-list; ER_Check != 1)'

        WHEN s4.[Drugs] != 0
         AND b.[Drugs] > 0
            THEN 'AMFS Rate x period multiplier x Quantity; fallback = Amount x 29% (Drugs CPT in Aetna_Drugs_CPTs; excl Modifier FB; excl contrast/radiopharmaceutical codes)'

        WHEN s4.[Implants] != 0
         AND (ISNULL(b.[Implants],0) + ISNULL(b.[Implant_V2790],0) + ISNULL(b.[implant_C1713],0)) > 0
            THEN 'Pct of charges: Amount x 36% (Implants Rev 274/275/276/278; or CPT V2790/C1713; excl device pass-through codes)'

        WHEN s4.[Blood] != 0
         AND b.[Blood] > 0
            THEN 'Pct of charges: Amount x 82% (Blood Rev 380-386/387/389)'

        WHEN s4.[Blood_Processing] != 0
         AND b.[Blood_Processing] > 0
            THEN 'Pct of charges: Amount x 74.1% (Blood Processing Rev 390/391/399)'

        WHEN s4.[OP_Default] != 0
         AND b.[OP_Default] > 0
            THEN 'Pct of charges: Amount x 74.1% - OP Default catch-all (CPT not excluded by contrast/radiopharmaceutical code list; or CPT IS NULL)'

        WHEN b.[COVID] != 0
            THEN 'COVID indicator flag - hardcoded 0 in this script (always zero); binary indicator, no dollar payment'

        WHEN b.[ER_Check] != 0
            THEN 'ER_Check indicator flag - binary 1 when Rev 450/451/452/459/456; used in hierarchy suppression logic; no dollar payment'

        WHEN b.[NeedsCorrectedClaim] != 0
            THEN 'NeedsCorrectedClaim flag - NCCI Modifier=1 bundling: line would pay but requires modifier 59/XE/XP/XS/XU; binary indicator, no dollar payment'

        ELSE 'Category suppressed by encounter hierarchy or no pattern matched - $0'
    END

    -- ----------------------------------------------------------------
    -- LINE PAYMENT
    -- MAX:              IIF(s4.[CAT]!=0, IIF(b.rn_CAT=1, value, 0), 0)
    -- SUM:              IIF(s4.[CAT]!=0, ISNULL(b.[CAT],0), 0)
    -- WINDOW_REDUCTION: slot-pivot from #bSlots keyed by EncounterID
    -- INDICATOR_FLAG:   $0 — never contribute flag value to LinePayment
    -- Implants sub-columns: sum all three sub-columns for LinePayment
    -- ----------------------------------------------------------------
    , [LinePayment] = ROUND(
          -- MAX categories
          IIF(s4.[Gamma_Knife] != 0,
              IIF(b.rn_Gamma_Knife = 1, ISNULL(b.[Gamma_Knife], 0), 0), 0)
        + IIF(s4.[Shoulder_Replacement] != 0,
              IIF(b.rn_Shoulder_Replacement = 1, ISNULL(b.[Shoulder_Replacement], 0), 0), 0)
        + IIF(s4.[Hip_Knee_Replacement] != 0,
              IIF(b.rn_Hip_Knee_Replacement = 1, ISNULL(b.[Hip_Knee_Replacement], 0), 0), 0)
        + IIF(s4.[PTCA] != 0,
              IIF(b.rn_PTCA = 1, ISNULL(b.[PTCA], 0), 0), 0)
        + IIF(s4.[Lithotripsy] != 0,
              IIF(b.rn_Lithotripsy = 1, ISNULL(b.[Lithotripsy], 0), 0), 0)
        + IIF(s4.[Lithotripsy_Injection] != 0,
              IIF(b.rn_Lithotripsy_Injection = 1, ISNULL(b.[Lithotripsy_Injection], 0), 0), 0)
        + IIF(s4.[Laparoscopy] != 0,
              IIF(b.rn_Laparoscopy = 1, ISNULL(b.[Laparoscopy], 0), 0), 0)
        + IIF(s4.[Cardiac_Cath] != 0,
              IIF(b.rn_Cardiac_Cath = 1, ISNULL(b.[Cardiac_Cath], 0), 0), 0)
        + IIF(s4.[Cardiac_Cath_Injection] != 0,
              IIF(b.rn_Cardiac_Cath_Injection = 1, ISNULL(b.[Cardiac_Cath_Injection], 0), 0), 0)
        + IIF(s4.[Minor_Surgery] != 0,
              IIF(b.rn_Minor_Surgery = 1, ISNULL(b.[Minor_Surgery], 0), 0), 0)
        + IIF(s4.[Endoscopy] != 0,
              IIF(b.rn_Endoscopy = 1, ISNULL(b.[Endoscopy], 0), 0), 0)
        + IIF(s4.[AS] != 0,
              IIF(b.rn_AS_flatrate = 1, ISNULL(b.[AS], 0), 0), 0)
        + IIF(s4.[ER] != 0,
              IIF(b.rn_ER = 1, ISNULL(b.[ER], 0), 0), 0)
        + IIF(s4.[Clinic] != 0,
              IIF(b.rn_Clinic = 1, ISNULL(b.[Clinic], 0), 0), 0)
          -- SUM categories
        + IIF(s4.[Psych] != 0,              ISNULL(b.[Psych], 0),              0)
        + IIF(s4.[ECT] != 0,                ISNULL(b.[ECT], 0),                0)
        + IIF(s4.[IOP] != 0,                ISNULL(b.[IOP], 0),                0)
        + IIF(s4.[Vascular_Angioplasty] != 0, ISNULL(b.[Vascular_Angioplasty], 0), 0)
        + IIF(s4.[Lab] != 0,                ISNULL(b.[Lab], 0),                0)
        + IIF(s4.[Radiation_Therapy] != 0,  ISNULL(b.[Radiation_Therapy], 0),  0)
        + IIF(s4.[Cardiac_Services] != 0,   ISNULL(b.[Cardiac_Services], 0),   0)
        + IIF(s4.[Chemotherapy] != 0,       ISNULL(b.[Chemotherapy], 0),       0)
        + IIF(s4.[Sleep_Studies] != 0,      ISNULL(b.[Sleep_Studies], 0),      0)
        + IIF(s4.[IV_Therapy] != 0,         ISNULL(b.[IV_Therapy], 0),         0)
        + IIF(s4.[Miscellaneous] != 0,      ISNULL(b.[Miscellaneous], 0),      0)
        + IIF(s4.[Drugs] != 0,              ISNULL(b.[Drugs], 0),              0)
          -- Implants: sum all three sub-columns confirmed in #Step3Bundle
        + IIF(s4.[Implants] != 0,
              ISNULL(b.[Implants], 0) + ISNULL(b.[Implant_V2790], 0) + ISNULL(b.[implant_C1713], 0),
              0)
        + IIF(s4.[Blood] != 0,              ISNULL(b.[Blood], 0),              0)
        + IIF(s4.[Blood_Processing] != 0,   ISNULL(b.[Blood_Processing], 0),   0)
        + IIF(s4.[OP_Default] != 0,         ISNULL(b.[OP_Default], 0),         0)
        + IIF(s4.[Radiology/MRI/CT_Scan_NoReduction] != 0,
              ISNULL(b.[Radiology/MRI/CT_Scan_NoReduction], 0), 0)
        + IIF(s4.[MRI/CT_noReduction] != 0,
              ISNULL(b.[MRI/CT_noReduction], 0), 0)
          -- WINDOW_REDUCTION: Radiology/MRI/CT_Scan_Reduction — slot-pivot from #bSlots
        + IIF(s4.[Radiology/MRI/CT_Scan_Reduction] != 0,
              CASE b.rn_Radiology_MRI_CT_Scan_Reduction
                WHEN 1  THEN ISNULL(rd.[RD1],  0)
                WHEN 2  THEN ISNULL(rd.[RD2],  0)
                WHEN 3  THEN ISNULL(rd.[RD3],  0)
                WHEN 4  THEN ISNULL(rd.[RD4],  0)
                WHEN 5  THEN ISNULL(rd.[RD5],  0)
                WHEN 6  THEN ISNULL(rd.[RD6],  0)
                WHEN 7  THEN ISNULL(rd.[RD7],  0)
                WHEN 8  THEN ISNULL(rd.[RD8],  0)
                WHEN 9  THEN ISNULL(rd.[RD9],  0)
                WHEN 10 THEN ISNULL(rd.[RD10], 0)
                ELSE 0
              END,
              0)
          -- WINDOW_REDUCTION: MRI/CT_Reduction — slot-pivot from #bSlots
        + IIF(s4.[MRI/CT_Reduction] != 0,
              CASE b.rn_MRI_CT_Reduction
                WHEN 1  THEN ISNULL(rd.[RDC1],  0)
                WHEN 2  THEN ISNULL(rd.[RDC2],  0)
                WHEN 3  THEN ISNULL(rd.[RDC3],  0)
                WHEN 4  THEN ISNULL(rd.[RDC4],  0)
                WHEN 5  THEN ISNULL(rd.[RDC5],  0)
                WHEN 6  THEN ISNULL(rd.[RDC6],  0)
                WHEN 7  THEN ISNULL(rd.[RDC7],  0)
                WHEN 8  THEN ISNULL(rd.[RDC8],  0)
                WHEN 9  THEN ISNULL(rd.[RDC9],  0)
                WHEN 10 THEN ISNULL(rd.[RDC10], 0)
                ELSE 0
              END,
              0)
          -- WINDOW_REDUCTION: PT/OT/ST — slot-pivot from #bSlots
        + IIF(s4.[PT/OT/ST] != 0,
              CASE b.rn_PT_OT_ST
                WHEN 1  THEN ISNULL(rd.[Therapy1],  0)
                WHEN 2  THEN ISNULL(rd.[Therapy2],  0)
                WHEN 3  THEN ISNULL(rd.[Therapy3],  0)
                WHEN 4  THEN ISNULL(rd.[Therapy4],  0)
                WHEN 5  THEN ISNULL(rd.[Therapy5],  0)
                WHEN 6  THEN ISNULL(rd.[Therapy6],  0)
                WHEN 7  THEN ISNULL(rd.[Therapy7],  0)
                WHEN 8  THEN ISNULL(rd.[Therapy8],  0)
                WHEN 9  THEN ISNULL(rd.[Therapy9],  0)
                WHEN 10 THEN ISNULL(rd.[Therapy10], 0)
                ELSE 0
              END,
              0)
          -- INDICATOR_FLAG: COVID, ER_Check, NeedsCorrectedClaim — $0, never add to LinePayment
      , 2)

    -- NCCI BUNDLED FLAG: NeedsCorrectedClaim from #Step3Bundle
    -- (NCCI bundle step exists in this script via UPDATE on #Step3Bundle)
    , [BundledByNCCI] = CAST(b.[NeedsCorrectedClaim] AS TINYINT)

    -- ----------------------------------------------------------------
    -- CONTRACT EFFECTIVE DATE FROM / TO
    -- Derived from ServiceDate using the master period list from the script.
    -- Periods read directly from all BETWEEN date ranges across all categories.
    -- ----------------------------------------------------------------
    , [ContractEffectiveDateFrom] = CASE
        WHEN b.[ServiceDate] BETWEEN '2020-04-01' AND '2021-03-31' THEN CAST('2020-04-01' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2021-04-01' AND '2022-03-31' THEN CAST('2021-04-01' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2022-01-01' AND '2022-03-31' THEN CAST('2022-01-01' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2022-04-01' AND '2023-03-31' THEN CAST('2022-04-01' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2023-02-01' AND '2023-03-31' THEN CAST('2023-02-01' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2023-04-01' AND '2023-06-30' THEN CAST('2023-04-01' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2023-07-01' AND '2024-03-31' THEN CAST('2023-07-01' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2024-04-01' AND '2025-03-31' THEN CAST('2024-04-01' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2025-04-01' AND '2026-03-31' THEN CAST('2025-04-01' AS DATE)
        ELSE NULL
      END

    , [ContractEffectiveDateTo] = CASE
        WHEN b.[ServiceDate] BETWEEN '2020-04-01' AND '2021-03-31' THEN CAST('2021-03-31' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2021-04-01' AND '2022-03-31' THEN CAST('2022-03-31' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2022-01-01' AND '2022-03-31' THEN CAST('2022-03-31' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2022-04-01' AND '2023-03-31' THEN CAST('2023-03-31' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2023-02-01' AND '2023-03-31' THEN CAST('2023-03-31' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2023-04-01' AND '2023-06-30' THEN CAST('2023-06-30' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2023-07-01' AND '2024-03-31' THEN CAST('2024-03-31' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2024-04-01' AND '2025-03-31' THEN CAST('2025-03-31' AS DATE)
        WHEN b.[ServiceDate] BETWEEN '2025-04-01' AND '2026-03-31' THEN CAST('2026-03-31' AS DATE)
        ELSE NULL
      END

INTO #LineBreakdown
FROM #bRanked b
INNER JOIN #Step4  s4  ON s4.[EncounterID]  = b.[EncounterID]
LEFT  JOIN #bSlots rd  ON rd.[EncounterID]  = b.[EncounterID]
ORDER BY b.[EncounterID], b.[Sequence];


--***********************************************************************************************************************************************************************************************************************************************************************************************************
Select *
	, [Drugs]
	+[Implants]
	+[Blood]
	+[Blood_Processing]
	+[Gamma_Knife]
	+[Shoulder_Replacement]	
	+[Hip_Knee_Replacement]	
	+[PTCA]					
	+[Lithotripsy]
	+[Lithotripsy_Injection]
	+[Laparoscopy]			
	+[Cardiac_Cath]
	+[Cardiac_Cath_Injection]
	+[AS]					
	+[Minor_Surgery]		
	+[Endoscopy]			
	+[ER]					
	+[Psych]
	+[ECT]
	+[IOP]					
	+[Vascular_Angioplasty]	
	+[Lab]					
	+[Radiation_Therapy]	
	+[PT/OT/ST]				
	+[Cardiac_Services]		
	+[Chemotherapy]			
	+[IV_Therapy]
	+[Sleep_Studies]		
	+[Miscellaneous]
	+[OP_Default]			
	+[MRI/CT_Reduction]
	+[Radiology/MRI/CT_Scan_Reduction]
	+[Radiology/MRI/CT_Scan_NoReduction]
	+[MRI/CT_noReduction]				


	as Price


INTO #Step5
FROM #Step4

--***********************************************************************************************************************************************************************************************************************************************************************************************************
Select
	x.*

	, y.[Price]
	, y.[Drugs]
	, y.[Implants]
	, y.[Blood]
	, y.[Blood_Processing]
	, y.[Gamma_Knife]
	, y.[Shoulder_Replacement]	
	, y.[Hip_Knee_Replacement]	
	, y.[PTCA]					
	, y.[Lithotripsy]
	, y.[Lithotripsy_Injection]
	, y.[Laparoscopy]			
	, y.[Cardiac_Cath]	
	, y.[Cardiac_Cath_Injection]
	, y.[AS]					
	, y.[Minor_Surgery]		
	, y.[Endoscopy]			
	, y.[ER]					
	, y.[Psych]
	, y.[ECT]
	, y.[IOP]					
	, y.[Vascular_Angioplasty]	
	, y.[Lab]					
	, y.[Radiation_Therapy]	
	, y.[PT/OT/ST]				
	, y.[Cardiac_Services]		
	, y.[Chemotherapy]			
