	, z.[RevCode12]
	, z.[CPT12]

Into #Step6
From [COL].[Data].[Demo] as x

	inner join #Step5 as y on x.[EncounterID] = y.[EncounterID]
	left join [COL].[Data].[Charges_With_CPT] as z on x.[EncounterID] = z.[EncounterID]

--***********************************************************************************************************************************************************************************************************************************************************************************************************	
SELECT
	x.[Hospital]
	, x.[HospitalCode]
	, x.[TypeOfBill]
	, x.[TypeOfBillNumeric]
	, x.[ID]
	, x.[EncounterID]
	, x.[PRS_ID]
	, x.[PatientLast]
	, x.[PatientFirst]
	, x.[PatientSex]
	, x.[PatientDOB]
	, x.[PaidDate]	
	, x.[ServiceDateFrom]
	, x.[ServiceDateTo]
	, DATEDIFF(DAY, x.[ServiceDateFrom], x.[ServiceDateTo]) AS [Length of Stay]	
	, x.[Contract]
	, x.[Plan]
	, x.[Payer01Code]
	, x.[Payer01Name]
	, x.[ServiceCode]
	, x.[ClaimCategory]
	, x.[ValueAmount1]
	, x.[ValueCode1]
	, x.[SubscriberID]
	, x.[BillCharges]
	, x.[Payer01Payment]
	, x.[Payer02Payment]
	, x.[PatientResponsibility]
	, x.[OriginalPayment]
	  
	, Round([Price], 2) as ExpectedPrice
	, Round([Price] - (cast(x.[OriginalPayment] as float)), 2) as Diff
	, Round((cast(x.[OriginalPayment] as float)/[BillCharges]) * 100, 2) as [% paid]
	
	, CASE 
	WHEN Price - (cast(x.[OriginalPayment] as float))> 10000 Then DATEDIFF(DAY, IsNULL(PaidDate,x.[ServiceDateTo]), GETDATE()) - 365 -30
	ELSE DATEDIFF(DAY, IsNULL(PaidDate,x.[ServiceDateTo]), GETDATE()) - 365
	END AS [DaysLeft]	
	
	, IIF(ISNULL(x.[Drugs]								,0) > 0,      'Drugs - '							+ Cast(x.[Drugs]								as varchar) + ', ','')
	+IIF(ISNULL(x.[Implants]							,0) > 0,      'Implants - '							+ Cast(x.[Implants]								as varchar) + ', ','')
	+IIF(ISNULL(x.[Blood]								,0) > 0,      'Blood - '							+ Cast(x.[Blood]								as varchar) + ', ','')
	+IIF(ISNULL(x.[Blood_Processing]					,0) > 0,      'Blood_Processing - '					+ Cast(x.[Blood_Processing]						as varchar) + ', ','')	
	+IIF(ISNULL(x.[Gamma_Knife]							,0) > 0,      'Gamma_Knife - '						+ Cast(x.[Gamma_Knife]							as varchar) + ', ','')
	+IIF(ISNULL(x.[Shoulder_Replacement]				,0) > 0,      'Shoulder_Replacement - '				+ Cast(x.[Shoulder_Replacement]					as varchar) + ', ','')
	+IIF(ISNULL(x.[Hip_Knee_Replacement]				,0) > 0,      'Hip_Knee_Replacement - '				+ Cast(x.[Hip_Knee_Replacement]					as varchar) + ', ','')
	+IIF(ISNULL(x.[PTCA]								,0) > 0,      'PTCA - '								+ Cast(x.[PTCA]									as varchar) + ', ','')
	+IIF(ISNULL(x.[Lithotripsy]							,0) > 0,      'Lithotripsy - '						+ Cast(x.[Lithotripsy]							as varchar) + ', ','')
	+IIF(ISNULL(x.[Lithotripsy_Injection]				,0) > 0,      'Lithotripsy_Injection - '			+ Cast(x.[Lithotripsy_Injection]				as varchar) + ', ','')
	+IIF(ISNULL(x.[Laparoscopy]							,0) > 0,      'Laparoscopy - '						+ Cast(x.[Laparoscopy]							as varchar) + ', ','')
	+IIF(ISNULL(x.[Cardiac_Cath]						,0) > 0,      'Cardiac_Cath - '						+ Cast(x.[Cardiac_Cath]							as varchar) + ', ','')
	+IIF(ISNULL(x.[Cardiac_Cath_Injection]				,0) > 0,      'Cardiac_Cath_Injection - '			+ Cast(x.[Cardiac_Cath_Injection]				as varchar) + ', ','')
	+IIF(ISNULL(x.[AS]									,0) > 0,      'AS - '								+ Cast(x.[AS]									as varchar) + ', ','')
	+IIF(ISNULL(x.[Minor_Surgery]						,0) > 0,      'Minor_Surgery - '					+ Cast(x.[Minor_Surgery]						as varchar) + ', ','')
	+IIF(ISNULL(x.[Endoscopy]							,0) > 0,      'Endoscopy - '						+ Cast(x.[Endoscopy]							as varchar) + ', ','')
	+IIF(ISNULL(x.[ER]									,0) > 0,      'ER - '								+ Cast(x.[ER]									as varchar) + ', ','')
	+IIF(ISNULL(x.[Psych]								,0) > 0,      'Psych - '							+ Cast(x.[Psych]								as varchar) + ', ','')
	+IIF(ISNULL(x.[ECT]									,0) > 0,      'ECT - '								+ Cast(x.[ECT]									as varchar) + ', ','')
	+IIF(ISNULL(x.[IOP]									,0) > 0,      'IOP - '								+ Cast(x.[IOP]									as varchar) + ', ','')
	+IIF(ISNULL(x.[Vascular_Angioplasty]				,0) > 0,      'Vascular_Angioplasty - '				+ Cast(x.[Vascular_Angioplasty]					as varchar) + ', ','')
	+IIF(ISNULL(x.[Lab]									,0) > 0,      'Lab - '								+ Cast(x.[Lab]									as varchar) + ', ','')
	+IIF(ISNULL(x.[Radiation_Therapy]					,0) > 0,      'Radiation_Therapy - '				+ Cast(x.[Radiation_Therapy]					as varchar) + ', ','')
	+IIF(ISNULL(x.[PT/OT/ST]							,0) > 0,      'PT/OT/ST - '							+ Cast(x.[PT/OT/ST]								as varchar) + ', ','')
	+IIF(ISNULL(x.[Cardiac_Services]					,0) > 0,      'Cardiac_Services - '					+ Cast(x.[Cardiac_Services]						as varchar) + ', ','')
	+IIF(ISNULL(x.[Chemotherapy]						,0) > 0,      'Chemotherapy - '						+ Cast(x.[Chemotherapy]							as varchar) + ', ','')
	+IIF(ISNULL(x.[Sleep_Studies]						,0) > 0,      'Sleep_Studies - '					+ Cast(x.[Sleep_Studies]						as varchar) + ', ','')
	+IIF(ISNULL(x.[Miscellaneous]						,0) > 0,      'Miscellaneous - '					+ Cast(x.[Miscellaneous]						as varchar) + ', ','')
	+IIF(ISNULL(x.[IV_Therapy]							,0) > 0,      'IV_Therapy - '						+ Cast(x.[IV_Therapy]							as varchar) + ', ','')
	+IIF(ISNULL(x.[OP_Default]							,0) > 0,      'OP_Default - '						+ Cast(x.[OP_Default]							as varchar) + ', ','')
	+IIF(ISNULL(x.[MRI/CT_Reduction]					,0) > 0,      'MRI/CT_Reduction - '					+ Cast(x.[MRI/CT_Reduction]						as varchar) + ', ','')
	+IIF(ISNULL(x.[Radiology/MRI/CT_Scan_Reduction]		,0) > 0,      'Radiology/MRI/CT_Scan_Reduction - '	+ Cast(x.[Radiology/MRI/CT_Scan_Reduction]		as varchar) + ', ','')
	+IIF(ISNULL(x.[Radiology/MRI/CT_Scan_NoReduction]	,0) > 0,      'Radiology/MRI/CT_Scan_NoReduction - '+ Cast(x.[Radiology/MRI/CT_Scan_NoReduction]	as varchar) + ', ','')
	+IIF(ISNULL(x.[MRI/CT_noReduction]					,0) > 0,      'MRI/CT_noReduction - '				+ Cast(x.[MRI/CT_noReduction]					as varchar) + ', ','')
	+IIF(ISNULL(x.[NeedsCorrectedClaim]					,0) > 0 and (ISNULL(x.[OP_Default]					        ,0) > 0 or ISNULL(x.[Radiology/MRI/CT_Scan_Reduction]						    ,0) > 0 or ISNULL(x.[Radiology/MRI/CT_Scan_NoReduction]						    ,0) > 0 or  ISNULL(x.[Lab]						    ,0) > 0),      'Needs Corrected Claim - Missing modifier 59,XE,XP,XS or XU  ','')
	
	as ExpectedDetailed	
		

